const body = $input.item.json.body || $input.item.json;
const base64 = body.archivo || body.file || body.base64;
if (!base64) throw new Error('No se recibió el campo archivo/file/base64 en el body');
const base64Clean = base64.replace(/^data:[^;]+;base64,/, '');
const nombreArchivo = body.nombre || body.filename || 'presupuesto.xlsx';
return [{
  json: { nombreArchivo, mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' },
  binary: {
    data: {
      data: base64Clean,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: nombreArchivo,
      fileExtension: nombreArchivo.split('.').pop()
    }
  }
}];

const filas = $input.all().map(item => item.json);
const texto = filas.map(fila => {
  return Object.entries(fila)
    .filter(([k, v]) => v !== null && v !== undefined && v !== '')
    .map(([k, v]) => `${k}: ${v}`)
    .join(' | ');
}).join('\n');
const nombreArchivo = $('Decodificar base').item.json.nombreArchivo;
return [{
  json: {
    nombreArchivo,
    contenidoExcel: texto,
    cantidadFilas: filas.length
  }
}];

const { nombreArchivo, contenidoExcel } = $('Preparar contenido1').item.json;

const ejemplosRaw = $input.all();

// Usar hasta 6 ejemplos aprobados (los más recientes)
// Si hay menos de 6, usar los que haya
const MAX_EJEMPLOS = 6;
const MAX_CHARS_EJEMPLOS = 30000; // límite total para no explotar el contexto

let bloqueEjemplos = '';
const ejemplosValidos = ejemplosRaw.filter(e => e.json.input_excel);

if (ejemplosValidos.length > 0) {
  const seleccionados = ejemplosValidos.slice(-MAX_EJEMPLOS);
  let charsUsados = 0;
  const bloques = [];

  for (const ej of seleccionados) {
    const inputText  = (ej.json.input_excel  || '').substring(0, 8000);
    const outputText = (ej.json.output_json  || '').substring(0, 6000);
    const bloque = `\n--- EJEMPLO (${ej.json.nombre_archivo || 'archivo'}) ---\nINPUT:\n${inputText}\nOUTPUT CORRECTO:\n${outputText}\n`;
    if (charsUsados + bloque.length > MAX_CHARS_EJEMPLOS) break;
    bloques.push(bloque);
    charsUsados += bloque.length;
  }

  if (bloques.length > 0) {
    bloqueEjemplos = `\n\nEJEMPLOS DE CONVERSIONES ANTERIORES CORRECTAS (aprendé de estos patrones):\n`;
    bloqueEjemplos += bloques.join('');
    bloqueEjemplos += `\n--- FIN DE EJEMPLOS (${bloques.length} usados de ${ejemplosValidos.length} disponibles) ---\n`;
  }
}

const systemPrompt = `Sos un experto en transformación de presupuestos de construcción.
Tu tarea es convertir presupuestos de cualquier formato al formato de importación estándar.

El formato de salida es un JSON con un array de filas, cada una con estos campos:
- Indice: string o número (ej: 1, 1.1, 1.1.1, 2, 2.1)
- Descripcion: string
- Codigo: string o null
- Cantidad: número o null
- Unidad: string (usar estas unidades estándar: tn, kg, l, un, gr, ml, m, cm, m2, m3, caja, pqt, doc, par, roll, bidon, dia, mes, glob, pomo, balde, plts, prto, hs, min, bol, mln)
- Modo: uno de estos valores exactos: RUBRO, AGRUPADOR, COMPONENTE, ARTICULO, RECETA

Reglas para asignar Modo:
- RUBRO: sección principal nivel 1. Sin cantidad propia.
- AGRUPADOR: agrupa componentes dentro de un rubro, sin cantidad propia
- COMPONENTE: sub-sección nivel 2 que agrupa artículos. Tiene cantidad y unidad.
- ARTICULO: ítem concreto con cantidad y unidad. Material, servicio o mano de obra.
- RECETA: ítem que corresponde a una mezcla existente (hormigón, pintura, revoque, etc.)

Reglas para el Índice:
- RUBRO: 1, 2, 3...
- COMPONENTE: 1.1, 1.2, 2.1...
- ARTICULO/RECETA: 1.1.1, 1.1.2, 1.2.1...

Reglas para la Cantidad:
- Si tiene fórmula Excel (ej: =250+400), calcular el resultado numérico
- Si no tiene cantidad (rubros, agrupadores), poner null
- Redondear a 2 decimales máximo
${bloqueEjemplos}
Respondé ÚNICAMENTE con un JSON válido, sin texto adicional, sin markdown, sin backticks.
Formato exacto: [{"Indice":"1","Descripcion":"...","Codigo":null,"Cantidad":1,"Unidad":"glob","Modo":"RUBRO"}, ...]`;

return [{
  json: {
    nombreArchivo,
    contenidoExcel,
    systemPrompt,
    cantidadEjemplos: ejemplosValidos.length
  }
}];

const { nombreArchivo, contenidoExcel, systemPrompt } = $input.item.json;

const apiKey = $vars.OPENAI_API_KEY || '';
if (!apiKey) throw new Error('Falta variable OPENAI_API_KEY en el workflow');

const userPrompt = `Convertí este presupuesto al formato estándar:\n\nArchivo: ${nombreArchivo}\n\nContenido:\n${contenidoExcel}`;

const https = require('https');

const body = JSON.stringify({
  model: 'gpt-4o',
  max_tokens: 8000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
});

const texto = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.openai.com',
    path: '/v1/chat/completions',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`
    }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        if (parsed.error) reject(new Error(parsed.error.message));
        else resolve(parsed.choices[0].message.content.trim());
      } catch(e) {
        reject(new Error('Error parsing response: ' + data.substring(0, 200)));
      }
    });
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

let filas;
try {
  const limpio = texto.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
  filas = JSON.parse(limpio);
} catch(e) {
  throw new Error(`Error al parsear respuesta de IA: ${e.message}\nRespuesta: ${texto.substring(0, 500)}`);
}

return [{
  json: {
    nombreArchivo,
    contenidoExcel,
    filas,
    outputJson: texto,
    cantidadFilas: filas.length
  }
}];

const XLSX = require('xlsx');
const { nombreArchivo, filas } = $input.item.json;

const headers = ['Indice', 'Descripcion', 'Codigo', 'Cantidad', 'Unidad', 'Modo'];
const wsData = [headers];
for (const fila of filas) {
  wsData.push([
    fila.Indice ?? '',
    fila.Descripcion ?? '',
    fila.Codigo ?? null,
    fila.Cantidad ?? null,
    fila.Unidad ?? '',
    fila.Modo ?? ''
  ]);
}
const ws = XLSX.utils.aoa_to_sheet(wsData);
ws['!cols'] = [{ wch: 12 },{ wch: 60 },{ wch: 15 },{ wch: 12 },{ wch: 10 },{ wch: 15 }];

const configData = [
  ['Unidad', null, null, 'Tipo', null, 'Moneda'],
  ['Toneladas','tn',null,'RUBRO','Nivel 1','USD'],
  ['Kilos','kg',null,'AGRUPADOR','Agrupador de componentes','ARS'],
  ['Litros','l',null,'COMPONENTE','Nivel 2','UYU'],
  ['Unidad','un',null,'ARTICULO','Nivel 3','COL'],
  ['Gramo','gr',null,'RECETA','Asociado a una receta existente','PYG'],
  ['Mililitro','ml'],['Metro','m'],['Centímetro','cm'],['Metro cuadrado','m2'],
  ['Metro cúbico','m3'],['Caja','caja'],['Paquete','pqt'],['Docena','doc'],
  ['Par','par'],['Rollo','roll'],['Bidón','bidon'],['Dia','dia'],['Mes','mes'],
  ['Global','glob'],['Pomo','pomo'],['Balde','balde'],['Pallets','plts'],
  ['Proyecto','prto'],['Horas','hs'],['Minutos','min'],['Bolsa','bol'],['Metro lineal','mln']
];
const wsConfig = XLSX.utils.aoa_to_sheet(configData);

const wb = XLSX.utils.book_new();
XLSX.utils.book_append_sheet(wb, ws, 'Presupuesto');
XLSX.utils.book_append_sheet(wb, wsConfig, 'Configuraciones');

const buffer = XLSX.write(wb, { type: 'base64', bookType: 'xlsx' });
const nombreSalida = nombreArchivo.replace(/\.(xlsx|xls)$/i, '') + '_importacion.xlsx';

return [{
  json: { nombreSalida, cantidadFilas: filas.length },
  binary: {
    data: {
      data: buffer,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: nombreSalida,
      fileExtension: 'xlsx'
    }
  }
}];
